mapper.select:
SELECT avi.mgr_seq, avi.rqst_mgr_seq, avi.cctv_mgr_no, avi.sec_st_dat, avi.sec_ed_dat, avi.play_limit_cnt, avi.play_limit_dat, avi.avi_conts_id, avi.hdd_serial, avi.mac_serial, avi.bak_stat_cd
        , vdwk.file_seq AS vdwk_file_seq, vdwk.file_nm AS vdwk_file_nm, vdwk.down_cnt AS vdwk_down_cnt, vdwk.sec_st_dat AS vdwk_sec_st_dat, vdwk.sec_ed_dat AS vdwk_sec_ed_dat
        , vdwk.work_stat_cd AS vdwk_work_stat_cd, vdwk_work_stat_cd_rel.cde_nm AS vdwk_work_stat_cd_rel_cde_nm, vdwk.work_rslt_msg as vdwk_work_rslt_msg
        , cctv_no_rel.cctv_nm AS cctv_no_rel_label

FROM xeus.crms_prev_avi AS avi

LEFT JOIN xeus.crms_prev_work AS vdwk                   ON vdwk.avi_mgr_seq = avi.mgr_seq
                                                        AND vdwk.rqst_mgr_seq = avi.rqst_mgr_seq
LEFT JOIN xeus.mt_cmm_cde AS vdwk_work_stat_cd_rel      ON vdwk_work_stat_cd_rel.grp_cde = 'C57'
                                                        AND vdwk_work_stat_cd_rel.cde_cde = vdwk.work_stat_cd
LEFT JOIN xeus.asset_cctv AS cctv_no_rel                ON cctv_no_rel.mgr_no = avi.cctv_mgr_no



        AND avi.mgr_seq = #{mgrSeq}::numeric



        AND avi.rqst_mgr_seq = #{rqstMgrSeq}::numeric



        AND avi.cctv_mgr_no = #{cctvMgrNo}



        AND avi.sec_st_dat = #{secStDat}



        AND avi.sec_ed_dat = #{secEdDat}



        AND avi.play_limit_cnt = #{playLimitCnt}::numeric



        AND avi.play_limit_dat = #{playLimitDat}



        AND avi.avi_conts_id = #{aviContsId}



        AND avi.hdd_serial = #{hddSerial}



        AND avi.mac_serial = #{macSerial}



        AND avi.bak_stat_cd = #{bakStatCd}





        ${sortCol} ${sortTyp}


        avi.mgr_seq ASC




    LIMIT ${limit} OFFSET ${offset}

mapper.update:
UPDATE xeus.crms_prev_avi
SET
    cctv_mgr_no = #{cctvMgrNo}
    , sec_st_dat = #{secStDat}
    , sec_ed_dat = #{secEdDat}
    , play_limit_cnt = #{playLimitCnt}::numeric
    , play_limit_dat = #{playLimitDat}
    , avi_conts_id = #{aviContsId}
    , hdd_serial = #{hddSerial}
    , mac_serial = #{macSerial}
    , bak_stat_cd = #{bakStatCd}

WHERE mgr_seq = #{mgrSeq}::numeric
    AND rqst_mgr_seq = #{rqstMgrSeq}::numeric;

mapper.delete:
DELETE FROM xeus.crms_trans_avi
WHERE rqst_mgr_seq = ${rqstMgrSeq}::numeric
        AND mgr_seq = ${aviMgrSeq}::numeric;
